    val result = mutableListOf<Long>()

    // 3. Check validity for each element
    for (i in 0 until n) {
        var isValid = false

        if (i == 0 || i == n - 1) {
            // First and last elements are always valid
            isValid = true
        } else {
            // Check Left condition: nums[i] > max(nums[0]...nums[i-1])
            // max(nums[0]...nums[i-1]) is L[i-1]
